-- Loot items
item.empty_plastic_can = "Пустая пластиковая банка"
item.empty_plastic_can.desc = "Пустая пластиковая банка. Выглядит очень изношенной и невозможно определить что в ней хранили раньше."
item.empty_chinese_takeout = "Пустая картонная коробка"
item.empty_chinese_takeout.desc = "Пустая картонная коробка из под китайской лапши."
item.empty_carton = "Пустая картонная упаковка"
item.empty_carton.desc = "Пустая картонная упаковка из под молока."
item.empty_tin_can = "Пустая консервная банка"
item.empty_tin_can.desc = "Старая пустая консервная банка, все надписи стёрты."
item.empty_jug = "Пустой пластиковый кувшин"
item.empty_jug.desc = "Пустой пластиковый кувшин из под молока."
item.empty_plastic_bottle = "Пустая пластиковая бутылка"
item.empty_plastic_bottle.desc = "Пустая пластиковая бутылка большого размера."
item.empty_can = "Пустая банка"
item.empty_can.desc = "Пустая алюминиевая банка."
item.empty_glass_bottle = "Пустая стеклянная бутылка"
item.empty_glass_bottle.desc = "Пустая стеклянная бутылка, похоже, что из под какого-то алкоголя."
item.junk_audiosystem = "Разобранная аудиосистема"
item.junk_audiosystem.desc = "Корпус из лугкого материала с простыми линиями и множеством разъемов. Внутренности раскрыты, динамики вынуты из корпуса, провода неряшливо сплетены в клубок."
item.junk_axel = "Автомобильный вал"
item.junk_axel.desc = "Гладкий и массивный часть трансмиссии машины, изготовленный из прочного металла. Его форма напоминает цилиндр с заостренными концами. На поверхности видны небольшие выступы и углубления, предназначенные для лучшего сцепления с другими частями механизма."
item.junk_bicycle = "Велосипед"
item.junk_bicycle.desc = "Старый велосипед с видимыми признаками износа: пыльные колеса, ржавая рама, потертые ручки руля и потрескавшееся седло. Несколько спиц сломаны, а цепь выскочила. Ржавые педали и ободья колёс добавляют ушедшей эпохи истории."
item.junk_bombastick = "Бутылка \"Бомбастик\""
item.junk_bombastick.desc = "Белый пластиковый контейнер с яркой голубой крышечкой, содержащий едкую кислотную щелочь. На этикетке виден яркий символ опасности и предупреждение о содержании вредных химических веществ. Детям не давать."
item.junk_briefcase = "Старый саквояж"
item.junk_briefcase.desc = "Изношенный кожаный саквояж темно-коричневого цвета с металлическими замками и ручками. На нем видны потертости и царапины, свидетельствующие о многих путешествиях."
item.junk_calculator = "Калькулятор"
item.junk_calculator.desc = "Небольшое устройство, обычно прямоугольной формы, выполненное из пластика. Имеет ряд кнопок, расположенных на панели передней части, каждая из которых обозначает цифру, операцию или функцию. На верхней части калькулятора расположен работающий дисплей."
item.junk_carbattery = "Аккумулятор"
item.junk_carbattery.desc = "Автомобильный аккумулятор с плоскими, вытекшими из него кислотными пятнами на корпусе. Из него исходит слабый запах серы, а положительные и отрицательные контакты покрыты слоем окиси."
item.junk_cardoor = "Оторванная дверь"
item.junk_cardoor.desc = "Представляет собой тяжелую металлическую дверь от автомобиля. Она с измятой поверхностью, испещренная царапинами и пятнами ржавчины, а также поврежденные петли и ручку."
item.junk_chair = "Раскладной стул"
item.junk_chair.desc = "Обычный потрепанный стул изготовленый из металла, его поверхность покрыта слоем ржавчины. На спинке и сиденье есть заметные потертости и царапины, а в некоторых местах краска отслоилась, обнажив металлическую основу."
item.junk_circuit = "Перегоревшая электроника"
item.junk_circuit.desc = "Выглядит как обычное электронное устройство, но имеет явные признаки повреждения или поломки из-за перегрева. На корпусе видны следы обугливания и плавления пластмассы, разбухшие элементы, вытекший электролит и дымные отложения."
item.junk_cid = "Сломанная CID карта"
item.junk_cid.desc = "Эту карту кто-то намеренно сломал, из-за чего использовать ее более не предоставляется возможным. Бывший владелец также предусмотрительно стер с нее какие-либо данные. Более ничего интересного на ней нет."
item.junk_citizenradio = "Сгоревшее радио"
item.junk_citizenradio.desc = "Старый портативный радиоприемник, покрытый слоями грязи, пыли и сажи. Кнопки и регуляторы выглядят изношенными и залипшими от долгой эксплуатации. На передней панели видны размытые надписи и цифры, часть из которых стерлась или обуглилась."
item.junk_clock = "Настольные часы"
item.junk_clock.desc = "Деревянный корпус покрыт множеством мелких царапин и потертостей. Циферблат, заметно выцветший и потускневший со временем, демонстрирует тонкую патину,"
item.junk_clock2 = "Настенные часы"
item.junk_clock2.desc = "Обычные часы, но их стрелки застыли на случайном времени, а циферблат покрыт пылью. Cтекло отсутствует вовсе, позволяя видеть внутренние механизмы."
item.junk_clothes = "Рваная одежда"
item.junk_clothes.desc = ""
item.junk_cupboard = "Деревянный шкафчик"
item.junk_cupboard.desc = "Кусочек природы, превращенный в функциональный и привлекательный предмет мебели. Дерево, некогда теплое и прочное, теперь обветшало и ослаблено, гниль и трещины расползаются по поверхности."
item.junk_cwuturtle = "Рваная черепашка ГСР"
item.junk_cwuturtle.desc = "Реликвия ушедших времен. Эта черепашка Союза Рабочих видала и лучшие времена - когда-то, возможно, она принадлежала кому-то и о ней заботились, но после инцидента, произошедшего давным давно, ее кто-то потерял."
item.junk_desklamp = "Настольная лампа"
item.junk_desklamp.desc = "Она обладает металлическим корпусом с пластиковым абажуром, состоит из прочной основы, обеспечивающей стабильность, и опорного стержня. Опора лампы, хоть и немного наклонена, все еще устойчиво держит свою позицию, а старые провода, обмотанные липким скотчем, пробегают вдоль нее."
item.junk_deskfan = "Настольный вентилятор"
item.junk_deskfan.desc = "Обычная настольная модель с металлической основой и пластиковыми лопастями. Он выглядит изношенным и сломанным: лопасти повреждены, несколько из них отсутствуют, а корпус помят."
item.junk_doll = "Детская кукла"
item.junk_doll.desc = "Очень старая пластиковая кукла с которой когда-то раньше игрались дети, сейчас лишь видно что краски выцвели, поверхность покрыта мелкими царапинами и потертостями."
item.junk_drawerchunk = "Деревянный ошметок"
item.junk_drawerchunk.desc = "Обломанная часть какой-то мебели, что теперь пришла в негодность. Структура дерева от гладких участков до грубых, образованных годами использования."
item.junk_engine = "Двигатель"
item.junk_engine.desc = "Крупный механизм с множеством перемычек, зубчатых колес и трубопроводов. Кажется, что части двигателя сборочные, но разбросаны и разрушены, в центре можно разглядеть фрагменты поршней и металлических стержней, которые когда-то работали."
item.junk_geiger = "Сломанный счетчик Гейгера"
item.junk_geiger.desc = "Небольшое устройство размером примерно с карманный калькулятор. Его корпус обычно выполнен из пластика или металла и имеет простой дисплей с цифровыми или аналоговыми показателями. Поврежденная поверхность корпуса, вся царапинах или трещинах на экране, а также отсутствии реакции на радиацию."
item.junk_gloves = "Рваные перчатки"
item.junk_gloves.desc = ""
item.junk_gurevich = "Статуэтка"
item.junk_gurevich.desc = "Маленький гипсовый памятник, потрескавшийся на несколько кусочков. Кажется, она изображает человека, но все равно даже из-за повреждений можно определить его тучную фигуру одного из деятелей Сити-8."
item.junk_harddrive = "Системный блок"
item.junk_harddrive.desc = "Металлический корпус блока обветшал, отчего видны следы времени и небрежного обращения. Внутренности усыпаны разноцветными проводами, пластиковыми деталями и металлическими компонентами, выглядят как запутанный клубок технологических деталей и чипов."
item.junk_huladoll = "Статуэтка гавайской принцессы"
item.junk_huladoll.desc = "Забавный предмет, изображающий гавайскую девицу, забавно двигающей своим тазом. Лицо давным давно стерлость, но движущий тельцем механизм все еще работает."
item.junk_keyboard = "Клавиатура"
item.junk_keyboard.desc = "На её поверхности видны явные следы износа: выцветшие клавиши, потертые буквы и цифры, мелкие царапины и потертости по всему корпусу. В некоторых частях еще отсутствую клавиши."
item.junk_lamp = "Перегоревший торшер"
item.junk_lamp.desc = "Старый металлический торшер с пылью и паутиной. От его верхней части отсутствует тканный плафон, который когда-то, вероятно, сиял мягким светом, но теперь осталась лишь черная угольная пятна и запах горелой проволоки."
item.junk_lantern = "Масляная лампа"
item.junk_lantern.desc = "Металлический корпус лампы покрыт сколами, а поверхность матовая от долгого использования. Стеклянный резервуар, исцарапанный и покрытый пылью, выделяется из темного металла. Ручка для переноски, с годами, потеряла свою первоначальную гладкость. Внутри видно остатки высохшего масла."
item.junk_metalbucket = "Ржавое ведро"
item.junk_metalbucket.desc = "На первый взгляд ничего не выделяет среди других старых металлических ведер. Его поверхность усыпана осыпающимися кусочками ржавого металла, а по бокам видны следы потертостей и сколов, а некоторые участки покрыты патиной."
item.junk_metalgascan = "Пустая канистра"
item.junk_metalgascan.desc = "Изношенный металлический контейнер с отчетливыми следами ржавчины. Его форма проста и функциональна, с зауженным горлом, позволяющим легко налить или вылить содержимое.  Внутри канистры нет ни капли жидкости, лишь запах бензина едва ощутим из под старого, потертого пробкодержателя."
item.junk_metalbucket2 = "Стальной таз"
item.junk_metalbucket2.desc = "Круглый сосуд, изготовленный из прочной стали. Он имеет гладкую поверхность и высокие бортики, образующие вместительное пространство внутри."
item.junk_metalpot = "Сгоревшая сковорода"
item.junk_metalpot.desc = "Поверхность сковородки покрыта потертостями и небольшими вмятинами, следы длительного использования. Ручка ободрана, исцарапана и немного сколота на краю. На дне сковороды видны яркие следы гари и пригоревших кусков пищи."
item.junk_monitor = "Монитор"
item.junk_monitor.desc = "Полуразобранный монитор, с трещинами по поверхности пластика и зацепками проводов, выглядящих, будто они могут оторваться в любую секунду. Пластиковый корпус потерял блеск, на нём видны неразборчивые следы от ударов и затемненные участки на экране."
item.junk_muffler = "Автомобильный глушитель"
item.junk_muffler.desc = "Металлическое устройство, предназначенное для уменьшения шума, создаваемого выхлопными газами двигателя автомобиля. Видимо после вторжения мало уже кому нужны автомобили, так что от этой детали прока нет, скорее всего."
item.junk_newspaper = "Старая газета"
item.junk_newspaper.desc = "Полусвернутая, покрытая пылью и пятнами возраста. Ее бумага потеряла белизну, буквы на заголовках и статьях обрывочно читаемы, словно. Страницы легко осыпаются при касании, оставляя следы пыли на руках."
item.junk_paintcan = "Банка из под краски"
item.junk_paintcan.desc = "Металлическая банка с закручивающейся крышкой, покрыта разводами и кляксами высохшей краски различных оттенков. На крышке банки видны следы открывания — маленькая заусенца на краю, указывающая на то, что ее использовали неоднократно."
item.junk_pipe = "Ржавая труба"
item.junk_pipe.desc = "Металлический цилиндр с поверхностью, покрытой коричневым слоем ржавчины, по которому когда-то шла вода. Сейчас такое лишь может пригодиться для удара кому-то по голове."
item.junk_plasticbucket = "Пластиковое ведро"
item.junk_plasticbucket.desc = "Ведро, изготовленное из крепкого белого пластика. Оно имеет круглое дно и высокие стенки, достаточно прочные, чтобы выдерживать вес жидкости или мусора. На боковой стороне  была стерта маркировка или логотоп."
item.junk_plasticcrate = "Пластиковая корзина"
item.junk_plasticcrate.desc = "Форма корзины прямоугольная с заостренными углами и перфорированной сеткой. Удобные ручки по бокам облегчают транспортировку и перемещение."
item.junk_pot = "Дырявый чайник"
item.junk_pot.desc = "Металлический чайник старого образца, выглядящий изношенным и покрытым ржавчиной. На его поверхности видны многочисленные дырки разного размера, словно он был подвергнут долголетнему использованию без должного ухода."
item.junk_pot2 = "Старая кастрюля"
item.junk_pot2.desc = "Поверхность кастрюли покрыта устойчивым слоем затертости. Покрыта пятнами ржавчины, а ручка и крышка облезлая от времени. Многочисленные царапины и следы от огня свидетельствуют о долгой службе."
item.junk_propane = "Пустой баллон"
item.junk_propane.desc = "Верхняя часть баллона закрыта крышкой с резьбой, а нижняя часть имеет плоское основание. Имеет круглую форму, с закругленными краями и небольшим клапаном на вершине. Вес был легким, так как внутри отсутствует газ."
item.junk_radiator = "Ржавая батарея"
item.junk_radiator.desc = "Некогда старый предмет быта, через который проходило отопление. От года износа его металлическая поверхность выглядит поистертой и истлевшей от времени, с заметными следами окисления."
item.junk_radio = "Сломанная рация"
item.junk_radio.desc = ""
item.junk_robustin = "Моющее средство \"Робастин\""
item.junk_robustin.desc = "\"Робастин\" представляют собой бутылку с средством для очистки различных поверхностей. Она обладает сильным очищающим действием, но если попадет на кожу, то кожа точно слезет."
item.junk_rolex = "Золотые часы"
item.junk_rolex.desc = "На первый взгляд – золотые часы, однако ближе к ним оказываются обычные детские часы взрослого стиля из дешевого пластика с нарисованным циферблатом. Отсутствие механизма и заметный недостаток веса лишь усиливают впечатление, что эти часы не предназначены для серьезного использования."
item.junk_suitcase = "Кожаный чемодан"
item.junk_suitcase.desc = "Старый и потрепанный чемодан, покрытый тонким слоем пыли и грязи. Кожаная поверхность облезла на многих местах, а зацепки и замки уже давно перестали надежно функционировать."
item.junk_shoe = "Башмак"
item.junk_shoe.desc = "Установить где находится левый не получилось, да и сам ботинок явно видал лучшие времена - порванная кожа и отсутствующие элементы ботинка дают явно понять, что его лучше выкинуть, чем пытаться чинить."
item.junk_tire = "Шина"
item.junk_tire.desc = "Изодранный кусок резины, обрывки проволоки торчат из поврежденного бока. Следы песка и грязи на шине свидетельствуют о несчастном случае или долгом пути."
item.junk_tv = "Сломанный телевизор"
item.junk_tv.desc = "Старый кинескопический телевизор, покрытый пылью и мелкими царапинами на поверхности пластикового корпуса. Экран выглядит мутным, с трещинами и пятнами. Повреждения видны и на корпусе: уголки обломаны, а поверхность покрыта царапинами и пятнами."
item.junk_vcr = "Видеомагнитофон"
item.junk_vcr.desc = "Видеомагнитофон, обросший пылью и потерявший свой блеск с годами. Открыв кассетное отделение, можно увидеть засохшие следы магнитной ленты, а механизм закрытия крышки щелкает с громким скрипом."
item.junk_woodchair = "Деревянный стул"
item.junk_woodchair.desc = "Изготовленный из массива дерева, он имеет круглое сиденье и четыре прочных ножки. Несмотря на следы времени, стул все еще сохраняет свою функциональность."
item.junk_zippo = "Зажигалка 'Zippo'"
item.junk_zippo.desc = "Пустая и разобранная изнутри зажигалка фирмы 'Zippo'. Ныне ею не зажечь ни одной сигареты, но, кто знает, может быть какой-нибудь умелец сможет вернуть ее к жизни?"